import React, { useState, useContext } from 'react';
import { Star, Heart, Bookmark, Play, X, Loader2 } from 'lucide-react';

// Mock AuthContext for demo - replace with your actual AuthContext
const AuthContext = React.createContext({
  isAuthenticated: true,
});

// Mock services - replace with your actual services
const rateMovie = async (data) => {
  return new Promise(resolve => {
    setTimeout(() => resolve({ rating: data.rating }), 500);
  });
};

const checkUserRating = async (movieId) => {
  return new Promise(resolve => {
    setTimeout(() => resolve({ has_rated: false }), 300);
  });
};

const MovieCard = ({ 
  movie, 
  showRecommendationScore = false, 
  recommendationSources = [], 
  onRatingUpdate = null 
}) => {
  const { isAuthenticated } = useContext(AuthContext);
  const [showQuickRate, setShowQuickRate] = useState(false);
  const [quickRating, setQuickRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);
  const [isRating, setIsRating] = useState(false);
  const [userRating, setUserRating] = useState(null);
  const [imageError, setImageError] = useState(false);

  React.useEffect(() => {
    if (isAuthenticated && movie.id) {
      fetchUserRating();
    }
  }, [isAuthenticated, movie.id]);

  const fetchUserRating = async () => {
    try {
      const ratingData = await checkUserRating(movie.id);
      if (ratingData.has_rated) {
        setUserRating(ratingData.rating);
      }
    } catch (error) {
      // User hasn't rated this movie, which is fine
    }
  };

  const handleQuickRate = async (rating) => {
    if (!isAuthenticated) return;

    setIsRating(true);
    try {
      const ratingData = await rateMovie({
        movie_id: movie.id,
        rating: rating,
        review: ''
      });

      setUserRating(ratingData.rating);
      setShowQuickRate(false);

      if (onRatingUpdate) {
        onRatingUpdate(movie.id, rating);
      }
    } catch (error) {
      console.error('Error rating movie:', error);
      alert('Failed to rate movie. Please try again.');
    } finally {
      setIsRating(false);
    }
  };

  const handleMovieClick = () => {
    // In your actual implementation, replace this with your navigation logic
    console.log(`Navigate to /movies/${movie.id}`);
    // For example: navigate(`/movies/${movie.id}`);
  };

  const renderStars = (rating, interactive = false, size = 'small') => {
    const stars = [];
    const maxStars = 5;
    const displayRating = interactive ? (hoverRating || quickRating) : rating;
    const sizeClasses = {
      small: 'w-3 h-3',
      medium: 'w-4 h-4',
      large: 'w-5 h-5'
    };

    for (let i = 1; i <= maxStars; i++) {
      const filled = i <= displayRating;
      stars.push(
        <Star
          key={i}
          className={`${sizeClasses[size]} ${
            filled ? 'fill-yellow-400 text-yellow-400' : 'text-gray-400'
          } ${
            interactive 
              ? 'cursor-pointer hover:scale-110 transition-all duration-200' 
              : ''
          }`}
          onClick={interactive ? () => {
            setQuickRating(i);
            handleQuickRate(i);
          } : undefined}
          onMouseEnter={interactive ? () => setHoverRating(i) : undefined}
          onMouseLeave={interactive ? () => setHoverRating(0) : undefined}
        />
      );
    }

    return <div className="flex gap-0.5">{stars}</div>;
  };

  const getRecommendationBadge = () => {
    if (!showRecommendationScore || !recommendationSources || recommendationSources.length === 0) {
      return null;
    }

    const badgeText = recommendationSources.includes('collaborative') && recommendationSources.includes('content')
      ? 'Perfect Match'
      : recommendationSources.includes('collaborative')
        ? 'Similar Users'
        : recommendationSources.includes('content')
          ? 'Your Taste'
          : 'Recommended';

    const badgeColor = recommendationSources.length > 1 
      ? 'bg-green-500' 
      : recommendationSources.includes('collaborative')
        ? 'bg-blue-500'
        : 'bg-orange-500';

    return (
      <div 
        className={`absolute top-2 right-2 ${badgeColor} text-white px-2 py-1 rounded-full text-xs font-semibold z-10 backdrop-blur-sm bg-opacity-90`}
      >
        {badgeText}
      </div>
    );
  };

  const formatYear = (year) => {
    return year ? `(${year})` : '';
  };

  const truncateTitle = (title, maxLength = 30) => {
    if (!title) return '';
    return title.length > maxLength ? `${title.substring(0, maxLength)}...` : title;
  };

  const truncatePlot = (plot, maxLength = 100) => {
    if (!plot) return '';
    return plot.length > maxLength ? `${plot.substring(0, maxLength)}...` : plot;
  };

  // Generate a placeholder image based on movie title if poster fails
  const getPlaceholderImage = () => {
    const colors = [
      'from-purple-400 to-pink-400',
      'from-blue-400 to-purple-500',
      'from-green-400 to-blue-500',
      'from-yellow-400 to-red-500',
      'from-indigo-400 to-purple-600',
      'from-pink-400 to-red-500'
    ];
    const colorIndex = movie.id % colors.length;
    return colors[colorIndex];
  };

  return (
    <div className="group relative bg-white rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 hover:-translate-y-1 overflow-hidden">
      {getRecommendationBadge()}

      {/* Movie Poster Section */}
      <div className="relative aspect-[2/3] overflow-hidden bg-gray-100 cursor-pointer" onClick={handleMovieClick}>
        {!imageError && movie.poster_url ? (
          <img
            src={movie.poster_url}
            alt={movie.title}
            className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
            onError={() => setImageError(true)}
          />
        ) : (
          <div className={`w-full h-full bg-gradient-to-br ${getPlaceholderImage()} flex items-center justify-center text-white font-bold text-4xl`}>
            {movie.title?.charAt(0) || '?'}
          </div>
        )}

        {/* Overlay with plot and rating */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300">
          <div className="absolute bottom-0 left-0 right-0 p-4 text-white">
            <div className="flex items-center gap-2 mb-2">
              {renderStars(movie.avg_rating, false, 'small')}
              <span className="text-sm font-medium">
                {movie.avg_rating ? movie.avg_rating.toFixed(1) : 'No rating'}
              </span>
            </div>

            {movie.plot && (
              <p className="text-sm text-gray-200 leading-tight">
                {truncatePlot(movie.plot)}
              </p>
            )}
          </div>
        </div>

        {/* Play button overlay */}
        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity duration-300">
          <div className="bg-white/20 backdrop-blur-sm rounded-full p-3 hover:bg-white/30 transition-colors cursor-pointer">
            <Play className="w-6 h-6 text-white fill-current" />
          </div>
        </div>
      </div>

      {/* Movie Info Section */}
      <div className="p-4 space-y-3">
        {/* Title and Year */}
        <div>
          <h3 
            className="text-lg font-semibold text-gray-900 hover:text-blue-600 transition-colors duration-200 cursor-pointer"
            title={movie.title}
            onClick={handleMovieClick}
          >
            {movie.title}
          </h3>
          <p className="text-sm text-gray-500 mt-1">{formatYear(movie.year)}</p>
        </div>

        {/* User Rating Display */}
        {userRating && (
          <div className="flex items-center gap-2 p-2 bg-blue-50 rounded-lg border-l-4 border-blue-500">
            <span className="text-xs font-semibold text-blue-700">Your rating:</span>
            {renderStars(userRating.rating, false, 'small')}
          </div>
        )}

        {/* Quick Rating for Authenticated Users */}
        {isAuthenticated && !userRating && (
          <div className="space-y-2">
            {!showQuickRate ? (
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  setShowQuickRate(true);
                }}
                className="w-full bg-gradient-to-r from-blue-500 to-purple-600 text-white py-2 px-4 rounded-lg hover:from-blue-600 hover:to-purple-700 transition-all duration-200 font-medium text-sm disabled:opacity-50 disabled:cursor-not-allowed"
                disabled={isRating}
              >
                ⭐ Quick Rate
              </button>
            ) : (
              <div
                onClick={(e) => e.stopPropagation()}
                className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg border"
              >
                <span className="text-xs font-medium text-gray-700 flex-shrink-0">Rate:</span>
                {renderStars(quickRating, true, 'small')}
                <button
                  onClick={() => setShowQuickRate(false)}
                  className="ml-auto w-6 h-6 bg-red-500 hover:bg-red-600 text-white rounded-full flex items-center justify-center transition-colors text-xs"
                >
                  <X className="w-3 h-3" />
                </button>
              </div>
            )}
          </div>
        )}

        {/* Movie Metadata */}
        <div className="flex flex-col gap-1 text-xs text-gray-600">
          {movie.rating_count > 0 && (
            <div className="flex items-center gap-1">
              <Star className="w-3 h-3" />
              <span>{movie.rating_count} rating{movie.rating_count !== 1 ? 's' : ''}</span>
            </div>
          )}

          {showRecommendationScore && movie.recommendation_score && (
            <div className="flex items-center gap-1 text-green-600 font-medium">
              <Heart className="w-3 h-3" />
              <span>Match: {(movie.recommendation_score * 100).toFixed(0)}%</span>
            </div>
          )}
        </div>

        {/* Genres */}
        {movie.genres && movie.genres.length > 0 && (
          <div className="flex flex-wrap gap-1">
            {movie.genres.slice(0, 3).map(genre => (
              <span
                key={genre}
                className="px-2 py-1 bg-blue-100 text-blue-800 text-xs rounded-full font-medium"
              >
                {genre}
              </span>
            ))}
            {movie.genres.length > 3 && (
              <span className="px-2 py-1 bg-gray-100 text-gray-600 text-xs rounded-full">
                +{movie.genres.length - 3}
              </span>
            )}
          </div>
        )}
      </div>

      {/* Loading Overlay */}
      {isRating && (
        <div className="absolute inset-0 bg-white/90 backdrop-blur-sm flex items-center justify-center z-20">
          <Loader2 className="w-6 h-6 text-blue-500 animate-spin" />
        </div>
      )}
    </div>
  );
};

